> index 61caa55a4402..7c1ab4a57409 100644
> --- a/mm/vmalloc.c
> +++ b/mm/vmalloc.c

[ ... ]

> @@ -2385,29 +2392,25 @@ static bool __purge_vmap_area_lazy(unsigned long start, unsigned long end,
>  		nr_purge_helpers = atomic_long_read(&vmap_lazy_nr) / lazy_max_pages();
>  		nr_purge_helpers = clamp(nr_purge_helpers, 1U, nr_purge_nodes) - 1;
>  
> -		for_each_cpu(i, &purge_nodes) {
> -			vn = &vmap_nodes[i];
> +		for_each_vmap_node(vn) {
> +			vn->work_queued = false;
> +
> +			if (list_empty(&vn->purge_list))
> +				continue;
>  
>  			if (nr_purge_helpers > 0) {
>  				INIT_WORK(&vn->purge_work, purge_vmap_node);
> -
> -				if (cpumask_test_cpu(i, cpu_online_mask))
> -					schedule_work_on(i, &vn->purge_work);
> -				else
> -					schedule_work(&vn->purge_work);
> -
> +				vn->work_queued = schedule_drain_vmap_work(&vn->purge_work);
>  				nr_purge_helpers--;
>  			} else {

Does this leak the vmap_area structures if schedule_drain_vmap_work()
returns false?

If drain_vmap_wq is NULL (e.g., during early boot before the workqueue is
initialized), vn->work_queued is set to false, but the else branch is not
taken to execute purge_vmap_node() synchronously.

As a result, the unpurged items remain on vn->purge_list. On the next
invocation of __purge_vmap_area_lazy(), the list head is overwritten:

	for_each_vmap_node(vn) {
		INIT_LIST_HEAD(&vn->purge_list);

This would permanently leak the vmap_area objects and exhaust the kernel
virtual address space.

> -				vn->purge_work.func = NULL;
>  				purge_vmap_node(&vn->purge_work);
>  				nr_purged_areas += vn->nr_purged;
>  			}
>  		}
>  
> -		for_each_cpu(i, &purge_nodes) {
> -			vn = &vmap_nodes[i];
> -
> -			if (vn->purge_work.func) {
> +		/* Wait for completion if queued any. */
> +		for_each_vmap_node(vn) {
> +			if (vn->work_queued) {
>  				flush_work(&vn->purge_work);

Can this cause a workqueue rescuer deadlock under memory pressure?

The drain_vmap_wq is created with WQ_MEM_RECLAIM, giving it a single
rescuer thread. If normal workers are exhausted and the rescuer thread
picks up the top-level drain_vmap_work, it will queue the child
vn->purge_work items to the exact same workqueue and then block
indefinitely here in flush_work().

Since the rescuer is blocked waiting, it can never execute the child items
it is waiting for.

>  				nr_purged_areas += vn->nr_purged;
>  			}
>  		}

[ ... ]

